// 1. Sadə type alias
type ID = string | number;
let userId: ID = "abc123"; // Düzgündür
userId = 123; // Düzgündür
// userId = true; // Xəta: boolean ID tipinə uyğun deyil

// 2. Obyekt üçün type alias
type User = {
  name: string;
  age: number;
};
const user: User = { name: "Alice", age: 25 };

// 3. Literal type ilə type alias
type Status = "active" | "inactive";
let status: Status = "active"; // Düzgündür
// status = "pending"; // Xəta: "pending" Status tipində yoxdur

// 4. Funksiya üçün type alias
type MathOperation = (x: number, y: number) => number;
const add: MathOperation = (a, b) => a + b;

// 5. Type alias ilə array
type ItemList = { name: string; price: number }[];
const items: ItemList = [{ name: "Shirt", price: 50 }, { name: "Hat", price: 25 }];

