// Öz type aliases nümunəni yarat!
type User = {
  name: string;
  role: "admin" | "user";
};

function printUser(user: User): void {
  console.log(`${user.name} is ${user.role}`);
}

const user: User = { name: "Alice", role: "admin" };
printUser(user);

